import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the input size to 10 characters
        if (input.length() > 10) {
            System.out.println("Input size exceeds limit. Please enter up to 10 characters.");
            return;
        }

        String sanitizedInput = input.substring(0, Math.min(input.length(), 10)); // Truncate input if it's longer than 10 characters

        System.out.println("Hello, " + sanitizedInput);
    }
}

### Explanation:
취약유형: Buffer Overflow
